using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX 4 – ValidateOnBuild (new in .NET 9 Development) catches this captive dependency:
//   a Singleton capturing a Scoped service throws at startup. Changed to Scoped.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
builder.Services.AddHttpClient("api")
    // FIX 1 – Default primary handler is now SocketsHttpHandler; the old cast to
    //   HttpClientHandler throws InvalidCastException. Use ConfigurePrimaryHttpMessageHandler.
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false })
    // FIX 2 – Trace-level header values are redacted by default in .NET 9.
    //   Allowlist the non-sensitive headers you need for debugging.
    .RedactLoggedHeaders(h =>
        h != "Accept" && h != "Content-Type" && h != "X-Request-Id");
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // FIX 3 – ForwardedHeadersMiddleware now silently ignores X-Forwarded-* headers
    //   from proxies not in KnownProxies / KnownNetworks. Add your proxy IP(s).
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1")); // TODO: replace with actual proxy IP
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

